package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/** ORDER BY rows use a packed arena, a primitive stable sort, bounded top-K, and cleaned-up binary spill runs. */
public class LmdbNativePackedSortTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI type = vf.createIRI(EX, "type");
			IRI item = vf.createIRI(EX, "Item");
			IRI score = vf.createIRI(EX, "score");
			IRI bucket = vf.createIRI(EX, "bucket");
			for (int i = 0; i < 500; i++) {
				IRI subject = vf.createIRI(EX, "s" + i);
				connection.add(subject, type, item);
				connection.add(subject, score, vf.createLiteral((i * 37) % 20));
				connection.add(subject, bucket, vf.createLiteral("bucket-value-" + (i % 7)));
			}
		}
		resetCounters();
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void forcedSpillMatchesGenericOrderingAndDeletesEveryRun() {
		String query = query("");
		try (SailRepositoryConnection connection = repository.getConnection()) {
			assertThat(connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized).toString())
					.contains("NativeRows")
					.contains("orderSlots=[")
					.doesNotContain("orderSlots=[]");
		}
		List<String> generic = rowsWithProperty(NATIVE_FLAG, "false", query);
		resetCounters();
		List<String> nativeRows = rowsWithProperty(NativeSpillSort.MAX_BYTES_PROPERTY, "256", query);

		assertThat(nativeRows).isEqualTo(generic);
		assertThat(NativeSpillSort.SPILL_RUNS.get()).isGreaterThan(2L);
		assertThat(NativeSpillSort.SPILLED_ROWS.get()).isEqualTo(500L);
		assertThat(NativeSpillSort.DELETED_RUNS.get()).isEqualTo(NativeSpillSort.SPILL_RUNS.get());
	}

	@Test
	public void packedTopKMatchesGenericWithoutCreatingRuns() {
		String query = query(" LIMIT 13");
		List<String> generic = rowsWithProperty(NATIVE_FLAG, "false", query);
		resetCounters();
		List<String> nativeRows = rowsWithProperty(NativeSpillSort.MAX_BYTES_PROPERTY, "256", query);

		assertThat(nativeRows).isEqualTo(generic);
		assertThat(NativeSortBuffer.TOP_K_CANDIDATES.get()).isEqualTo(500L);
		assertThat(NativeSpillSort.SPILL_RUNS.get()).isZero();
		assertThat(NativeSortBuffer.PACKED_ROWS.get()).isEqualTo(13L);
	}

	@Test
	public void distinctTopKDeduplicatesBeforeBoundingTheHeap() {
		String query = "SELECT DISTINCT ?score ?bucket WHERE { ?s <" + EX + "type> <" + EX
				+ "Item> ; <" + EX + "score> ?score ; <" + EX + "bucket> ?bucket }"
				+ " ORDER BY ?bucket DESC(?score) LIMIT 13";
		try (SailRepositoryConnection connection = repository.getConnection()) {
			assertThat(connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized).toString())
					.contains("NativeRows")
					.contains("distinct=true")
					.doesNotContain("orderSlots=[]");
		}
		List<String> generic = rowsWithProperty(NATIVE_FLAG, "false", query);
		resetCounters();
		List<String> nativeRows = rowsWithProperty(NativeSpillSort.MAX_BYTES_PROPERTY, "256", query);

		assertThat(nativeRows).isEqualTo(generic);
		assertThat(NativeDistinctTracker.PRIMITIVE_ROWS.get()).isEqualTo(500L);
		assertThat(NativeSortBuffer.TOP_K_CANDIDATES.get()).isEqualTo(140L);
		assertThat(NativeSortBuffer.PACKED_ROWS.get()).isEqualTo(13L);
		assertThat(NativeSpillSort.SPILL_RUNS.get()).isZero();
	}

	private String query(String suffix) {
		return "SELECT ?s ?score ?bucket WHERE { ?s <" + EX + "type> <" + EX + "Item> ; <" + EX
				+ "score> ?score . OPTIONAL { ?s <" + EX + "bucket> ?bucket } }"
				+ " ORDER BY ?bucket DESC(?score) ?s" + suffix;
	}

	private List<String> rowsWithProperty(String property, String value, String query) {
		String previous = System.getProperty(property);
		try {
			System.setProperty(property, value);
			try (SailRepositoryConnection connection = repository.getConnection()) {
				List<String> rows = new ArrayList<>();
				for (BindingSet row : QueryResults.asList(connection.prepareTupleQuery(query).evaluate())) {
					rows.add(row.getBindingNames()
							.stream()
							.sorted()
							.map(name -> name + "=" + row.getValue(name).stringValue())
							.collect(Collectors.joining("|")));
				}
				return rows;
			}
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	private static void resetCounters() {
		NativeSortBuffer.PACKED_ROWS.set(0L);
		NativeSortBuffer.SORTS.set(0L);
		NativeSortBuffer.TOP_K_CANDIDATES.set(0L);
		NativeSpillSort.SPILL_RUNS.set(0L);
		NativeSpillSort.SPILLED_ROWS.set(0L);
		NativeSpillSort.DELETED_RUNS.set(0L);
		NativeDistinctTracker.PRIMITIVE_ROWS.set(0L);
		NativeDistinctTracker.OBJECT_ROWS.set(0L);
	}
}
